from flask import Flask, send_file
import os

app = Flask(__name__)

# Mock directory containing invoices
INVOICES_DIR = 'path/to/invoices'

@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    # Construct the file path for the invoice
    file_path = os.path.join(INVOICES_DIR, f'{invoice_id}.pdf')
    
    # Check if the file exists to prevent broken access control
    if not os.path.exists(file_path):
        return "Invoice not found", 404
    
    # Send the PDF file as a response
    return send_file(file_path, as_attachment=True)

if __name__ == '__main__':
    app.run(debug=True)